class Importer{constructor(){this.importerInput=document.getElementById("post-importer-input"),this.importerButton=document.getElementById("import-post-button"),this.importerButton.onclick=()=>{this.importPost(this.importerInput.value)}}get danbooruRegex(){return/https:\/\/danbooru\.donmai\.us\/posts\/(?<danbooruId>[\d]+)/}addTags(t){let e=document.getElementById("file-tags");e.value="";for(let o of t.tag_string_general.split(" "))e.value+=`${o} `;for(let o of t.tag_string_character.split(" "))e.value+=`char:${o} `;for(let o of t.tag_string_copyright.split(" "))e.value+=`cop:${o} `;for(let o of t.tag_string_artist.split(" "))e.value+=`art:${o} `}addFile(t){let e=document.getElementById("file-upload");fetch(t.file_url,{method:"GET"}).then(t=>t.blob()).then(o=>{let r=new File([o],t.file_url.split("/")[-1],{type:o.type,lastModified:(new Date).getTime()}),s=new DataTransfer;s.items.add(r),e.files=s.files;let i=new Event("change");e.dispatchEvent(i)}).catch(t=>console.error(t))}addSource(t){document.getElementById("file-source").value=t.source}importPost(t){this.danbooruRegex.test(t)||(alert("Invalid."),this.importerInput.value="");let e=this.danbooruRegex.exec(t)[1];fetch(`https://danbooru.donmai.us/posts/${e}.json`,{method:"GET"}).then(t=>t.json()).then(t=>{this.addTags(t),this.addFile(t),this.addSource(t)}).catch(t=>console.error(t))}}export{Importer};